'use strict';

// MODULES //

var ndarraylike2scalar = require( '@stdlib/ndarray-base-ndarraylike2scalar' );
var numelDimension = require( '@stdlib/ndarray-base-numel-dimension' );
var getStride = require( '@stdlib/ndarray-base-stride' );
var getOffset = require( '@stdlib/ndarray-base-offset' );
var getData = require( '@stdlib/ndarray-base-data-buffer' );
var strided = require( '@stdlib/blas-ext-base-gjoin-between' ).ndarray;


// MAIN //

/**
* Returns a string by joining one-dimensional ndarray elements using a specified separator for each pair of consecutive elements.
*
* ## Notes
*
* -   The function expects the following ndarrays:
*
*     -   a one-dimensional input ndarray.
*     -   a zero-dimensional ndarray containing a prefix string.
*     -   a zero-dimensional ndarray containing a suffix string.
*     -   a one-dimensional ndarray containing separator strings.
*
* @param {ArrayLikeObject<Object>} arrays - array-like object containing ndarrays
* @returns {string} joined string
*
* @example
* var vector = require( '@stdlib/ndarray-vector-ctor' );
* var scalar2ndarray = require( '@stdlib/ndarray-from-scalar' );
*
* var x = vector( [ 1, 2, 3, 4 ], 'generic' );
*
* var prefix = scalar2ndarray( 'op: ', {
*     'dtype': 'generic'
* });
*
* var suffix = scalar2ndarray( '', {
*     'dtype': 'generic'
* });
*
* var separators = vector( [ ' + ', ' - ', ' != ' ], 'generic' );
*
* var v = gjoinBetween( [ x, prefix, suffix, separators ] );
* // returns 'op: 1 + 2 - 3 != 4'
*/
function gjoinBetween( arrays ) {
	var separators;
	var prefix;
	var suffix;
	var x;

	x = arrays[ 0 ];
	prefix = ndarraylike2scalar( arrays[ 1 ] );
	suffix = ndarraylike2scalar( arrays[ 2 ] );
	separators = arrays[ 3 ];

	return strided( numelDimension( x, 0 ), prefix, suffix, getData( x ), getStride( x, 0 ), getOffset( x ), getData( separators ), getStride( separators, 0 ), getOffset( separators ) ); // eslint-disable-line max-len
}


// EXPORTS //

module.exports = gjoinBetween;
